def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 6):
            weight = 1 / j
            term = (ratio ** j) * weight
            if j % 2 == 0:
                term *= 1.2
            else:
                term *= 0.8
            score += term
        remaining = capacity - item
        if remaining < capacity * 0.05:
            score *= 2.0
        elif remaining < capacity * 0.1:
            score *= 1.5
        elif remaining < capacity * 0.3:
            score *= 1.2
        elif remaining > capacity * 0.7:
            score *= 0.5
        else:
            score *= 0.9
        penalty = 0
        for k in range(1, 4):
            penalty += (remaining / capacity) ** k / (k * 10)
        score += penalty
        if score > 1:
            score = 1 / score
        priorities[i] = score
    return priorities
